#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[2 * N];
        for (int i = 0; i < 2 * N; i++) {
            scanf("%d", &A[i]);
        }
        qsort(A, 2 * N, sizeof(int), compare);
        int B[N];
        for (int i = 0; i < N; i++) {
            B[i] = (i < N / 2) ? A[i * 2] : A[(N - 1 - i) * 2 + 1];
        }
        printf("%d\n", B[N / 2]);
        for (int i = 0; i < N; i++) {
            printf("%d ", A[i * 2]);
            printf("%d ", A[i * 2 + 1]);
        }
        printf("\n");
    }
    return 0;
}

