import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[2 * N];
            for (int i = 0; i < 2 * N; i++) {
                A[i] = sc.nextInt();
            }
            Arrays.sort(A);
            int[] B = new int[N];
            for (int i = 0; i < N; i++) {
                B[i] = (i < N / 2) ? A[i * 2] : A[(N - 1 - i) * 2 + 1];
            }
            System.out.println(B[N / 2]);
            for (int i = 0; i < N; i++) {
                System.out.print(A[i * 2] + " " + A[i * 2 + 1] + " ");
            }
            System.out.println();
        }
    }
}

